var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"간만에 뵙네요, 부사장님.","JPN":"お久しぶりです、副社長。","ENG":"It's been a while, Vice President.","TWN":"好久不見了，副總。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"출장은 잘 다녀오셨어요?","JPN":"出張はどうでしたか？","ENG":"How was your business trip?","TWN":"出差還順利嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"덕분에 편안히 다녀왔죠.","JPN":"おかげさまで無事行ってきました。","ENG":"Thanks to you, it went smoothly.","TWN":"托你的福，一切順利。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"반면에 서윤 양은 복귀 후 첫 임무부터 다사다난했더군요.","JPN":"逆にシズカさんは復帰後初の任務から大変でしたね。","ENG":"On the other hand, Seo Yoon, you had quite a turbulent first mission after your return.","TWN":"反倒是徐芸你，才剛複職就經歷了一次多災多難的任務呢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"임무에 실패할 조짐이 보이면 비상연락망으로 절 호출하라고 했는데, 결국 부르지 않았고요.","JPN":"任務に失敗すると思ったら非常連絡網を利用して私を呼びなさいと言っておいたのに、結局呼びませんでしたし。","ENG":"I told you to call me through the emergency contact if you saw signs of mission failure, but you never did.","TWN":"都說了如果覺得任務有可能失敗的話，一定要通過緊急聯絡系統呼叫我，但你終究是沒有那樣做。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"에이, 사소한 일로 바쁜 부사장님께 폐를 끼칠 순 없죠.","JPN":"いつも多忙な副社長ですからね。これくらいのことで迷惑をかけるわけにはいきませんよ。","ENG":"Oh, I couldn't bother the busy Vice President with such trivial matters.","TWN":"哎呀，這點小事怎麼能打擾事務纏身的副總你呢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"저희 둘만으로도 충분히 해낼 거라 확신했거든요.","JPN":"それに、私たち2人だけで十分できると確信しましたから。","ENG":"I was certain that the two of us could handle it.","TWN":"而且我也相信靠我們兩個足以解決問題。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자기 목숨이 걸린 도박을 확신이라고 표현하는 버릇은 좋지 않네요.","JPN":"自分の命をかけるばくちを確信と表現する癖はよくないですよ。","ENG":"It's not good to refer to a life-risking gamble with certainty.","TWN":"將自己的性命賭在信心之上可不是個好習慣呢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만…","JPN":"でも……","ENG":"However...","TWN":"不過……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"위기를 기회로 활용하는 임기응변은 확실히 나쁘지 않았습니다.","JPN":"ピンチをチャンスに変えるその臨機応変さは確かに悪くありませんでした。","ENG":"The ability to turn a crisis into an opportunity was certainly not bad.","TWN":"能將這點化為對危機的應變能力，確實值得表揚。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"감사합니다.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"謝謝你的認可。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이걸로 솔로베 양도 한층 회사 생활에 적응했으면 좋겠군요.","JPN":"これを機にソロベーさんも一層社会人として適応していけたらいいですね。","ENG":"I hope this will help Solovey adapt better to life at the company.","TWN":"希望這次事件能讓蘇羅薇更好地適應公司內的生活。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"함께 호흡도 맞춰봤으니 이 참에 알트 소대로 편입시키는 것도 고려해봐야겠네요.","JPN":"一緒に戦ってもみましたし、この際アルト小隊に編入させることも考えてみます。","ENG":"Since you've worked together, it might be a good idea to consider transferring her to the ALT squad.","TWN":"既然你們都已經一起出生入死過了，不妨考慮讓她加入阿爾特小隊怎麼樣？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그러면 저도 좋겠지만, 저희는 아직 4인 체제를 바꿀 계획이 없어서요.","JPN":"いい考えだとは思いますけど、うちの小隊はまだ4人体系を変えるつもりがなくて。","ENG":"I'd like that too, but we're not planning to change from a 4-person system yet.","TWN":"雖然我也很想這樣做，但我們暫時沒有調整四人編制的計畫。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"적어도 이곳 생활에 적응할 동안엔 동료 선배보다는 친구와 어울리는 게 좋을 것 같아요.","JPN":"少なくともここで生活している間は会社の先輩よりは友達とつるんだ方がいいと思います。","ENG":"At least while she's adjusting to life here, it might be better to hang out with friends rather than colleagues.","TWN":"至少在適應這裡的生活之前，比起前輩們，我更希望她能多和朋友們相處。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"친구라…","JPN":"友達ね……","ENG":"Friends…","TWN":"朋友的話……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 역할에 어울리는 적임자가 하나 있긴 하죠.","JPN":"その役割に合う適任者が1人いますね。","ENG":"There is someone well-suited for that role.","TWN":"確實還有個不錯的人選。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"어머, 돌아오셨군요. 부사장님. 마침 보고 드릴 게 있었는데 잘 됐네요.","JPN":"あら、おかえりなさい。副社長。ちょうど報告したいことがあったんです。","ENG":"Oh, you're back, Vice President. I'm glad I have something to report just in time.","TWN":"喔，你回來了，副總！正好，我有事要向你彙報。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이게 그 골칫거리 운석인가요?","JPN":"これが例の厄介な隕石ですか？","ENG":"Is this the troublesome meteorite?","TWN":"這就是那個讓人頭疼的隕石嗎？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"네, 정확히는 니블의 유체라고 볼 수 있는 형태죠.","JPN":"はい、正確にはニブルの幼体と言える形態です。","ENG":"Yes, it's actually a young form of Nibble, to be exact.","TWN":"是的，準確的說應該是蠶食的實體殘骸。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"인간 형태를 갖추기 시작한 건, 첫번째 카운터의 CRF를 빼앗은 직후였으니까요.","JPN":"人間の形をするようになったのは、最初のカウンターからCRFを奪った直後でしたから。","ENG":"She began to take on a human form right after she stole the first Counter's CRF.","TWN":"因為是在奪取第一位制裁者的CRF後，她才開始擁有穩定的人形。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇게 아무거나 먹어 대며 성장하던 녀석이 미스틸테인에 당한 순간 거부반응을 일으키며 전부 토해내곤… 이것만 남았다는 거군요.","JPN":"そうやって何でもかんでも食べて成長したやつがミスティルテインにやられた瞬間、拒否反応を起こして全部吐きだし……残ったのはこれだけってことですね。","ENG":"She grew by devouring anything. But the moment she was beaten by Misteltein, she had a rejection reaction and vomited everything up... And this is all that's left.","TWN":"也就是說瘋狂吞噬一切，不斷成長的怪物，卻在被米斯特丁攻擊時，產生了強烈的排斥反應，並把所有吸收的東西全部吐了出來……只剩下了這個。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"파기하기 위해 할 수 있는 시도는 다 해봤지만, 끄떡없더라고요.","JPN":"破棄するためにできることは全部やってみましたけど、傷すらつきません。","ENG":"We've tried everything to destroy her, but nothing worked.","TWN":"我們已經嘗試了所有能摧毀她的方法，但都無濟於事。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그래서 론 리 박사님의 끈질긴 설득 끝에 저희가 연구 샘플로 사용하게 됐습니다.","JPN":"それでローン・リー博士のしつこい説得に負け、私たちが研究サンプルとして使うことになりました。","ENG":"So, after Dr. Lone Lee's persistent persuasion, we decided to use her as a research sample.","TWN":"所以在隆利博士的堅持下，我們最終決定將其作為樣本進行研究。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이걸 제거할 방법을 연구한다는 뜻이겠죠?","JPN":"これを除去する方法を研究するということですよね？","ENG":"I believe that means you're researching how to eliminate her, right?","TWN":"你是說，要研究如何才能消除她，是嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"명목상으로는 그렇죠?","JPN":"名目上はそうですね？","ENG":"That's the official reason, right?","TWN":"名義上是這樣的。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하하…","JPN":"ハハ……","ENG":"Haha...","TWN":"哈哈……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};